examples.pattern:
/* CSS */
.mira-orb { position:relative; width:240px; height:240px; border-radius:50%; }
.mira-orb::before, .mira-orb::after,
.mira-orb .blob-2, .mira-orb .blob-3 {
  content:""; position:absolute; inset:0; border-radius:50%; filter:blur(30px);
}
.mira-orb::before { background: radial-gradient(circle, #EC4899 0%, transparent 60%); animation: drift-pink 9s ease-in-out infinite; }
/* ... 3 autres blobs avec délais -1.6s, -3.2s, -4.8s — ne pas tous partir à t=0 */

tl.from({ v: 0 }, {
  v: 5, duration: 1.2, ease: "power2.out",
  onUpdate: function() { document.querySelector("#sku-count").textContent = Math.round(this.targets()[0].v); }
}, 17);

const text = "Je pars en congés du 10 au 20 mai";
tl.to({ i: 0 }, {
  i: text.length, duration: 1.6, ease: "none",
  onUpdate: function() {
    const n = Math.round(this.targets()[0].i);
    document.querySelector("#prompt-text").textContent = text.slice(0, n);
  }
}, 11);
